import axios from 'axios';

function App() {
  const [form, setForm] = useState({ name: '', empId: '', salary: '', department: '' });
  const [employees, setEmployees] = useState([]);

  useEffect(() => { fetchEmployees(); }, []);

  const fetchEmployees = async () => {
